// ====== NAVIGATION ======
let navHistory = ['screen-onboarding'];
let isNavigating = false;

function goTo(id) {
  if (isNavigating) return;
  const current = document.querySelector('.screen.active');
  const next = document.getElementById(id);
  if (!next || current === next) return;
  isNavigating = true;
  current.classList.remove('active');
  current.classList.add('slide-out');
  setTimeout(() => current.classList.remove('slide-out'), 240);
  next.classList.add('active', 'slide-in');
  setTimeout(() => { next.classList.remove('slide-in'); isNavigating = false; }, 300);
  const navMap = { 'screen-home': 0, 'screen-menu': 1, 'screen-aichef': 2, 'screen-quest': 3 };
  const idx = navMap[id];
  if (idx !== undefined) {
    const navBtns = next.querySelectorAll('.nav-item');
    navBtns.forEach(b => b.classList.remove('active'));
    if (navBtns[idx]) navBtns[idx].classList.add('active');
  }
  navHistory = [...navHistory.filter(h => h !== id), id];
  if (id === 'screen-menu') initMenu();
  if (id === 'screen-quest') { questLevel = 0; initQuest(); }
  if (id === 'screen-order') renderOrderScreen();
  if (id === 'screen-aiphoto') resetAiPhoto();
}

function goBack() {
  if (navHistory.length > 1) {
    navHistory.pop();
    goTo(navHistory[navHistory.length - 1]);
  }
}

