let activeMenuCat = 'all';

function initMenu() { renderMenu(); }

function filterMenu(btn, cat) {
  document.querySelectorAll('.cat-btn').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  activeMenuCat = cat;
  renderMenu();
}

function renderMenu() {
  const list = document.getElementById('menuList');
  if (!list) return;
  const filtered = activeMenuCat === 'all' ? menuItems : menuItems.filter(i => i.cat === activeMenuCat);
  list.innerHTML = filtered.map(item => `
    <div class="menu-item">
      <div class="menu-item-emoji">${item.emoji}</div>
      <div class="menu-item-body">
        <div class="menu-item-name">${item.name}</div>
        <div class="ai-badge">🤖 AI-описание</div>
        <p class="menu-item-desc">${item.desc}</p>
        <div class="menu-item-footer">
          <span class="menu-item-price">${item.price}</span>
          <button class="add-btn" onclick="addToOrder(this)">+</button>
        </div>
      </div>
    </div>
  `).join('');
}

// ====== CART / ORDER ======
let cartItems = []; // { name, price (number), emoji, qty }

function addToOrder(btn) {
  // Find the menu item for this button
  const itemEl = btn.closest('.menu-item');
  if (!itemEl) return;
  const nameEl = itemEl.querySelector('.menu-item-name');
  const priceEl = itemEl.querySelector('.menu-item-price');
  const emojiEl = itemEl.querySelector('.menu-item-emoji');
  if (!nameEl || !priceEl) return;

  const name = nameEl.textContent.trim();
  const priceStr = priceEl.textContent.trim();
  const price = parseInt(priceStr.replace(/[^\d]/g, ''), 10) || 0;
  const emoji = emojiEl ? emojiEl.textContent.trim() : '🍜';

  const existing = cartItems.find(i => i.name === name);
  if (existing) {
    existing.qty++;
  } else {
    cartItems.push({ name, price, emoji, qty: 1 });
  }

  // Animate button
  btn.textContent = '✓';
  btn.style.background = '#22C55E';
  setTimeout(() => { btn.textContent = '+'; btn.style.background = ''; }, 1000);

  updateCartFab();
}

function updateCartFab() {
  const fab = document.getElementById('cartFab');
  const countEl = document.getElementById('cartCount');
  if (!fab || !countEl) return;
  const total = cartItems.reduce((s, i) => s + i.qty, 0);
  if (total > 0) {
    fab.style.display = 'flex';
    countEl.textContent = total;
  } else {
    fab.style.display = 'none';
  }
}

function clearOrder() {
  cartItems = [];
  updateCartFab();
  renderOrderScreen();
}

function renderOrderScreen() {
  const body = document.getElementById('orderBody');
  if (!body) return;

  if (cartItems.length === 0) {
    body.innerHTML = `
      <div class="order-empty">
        <div class="order-empty-icon">🛒</div>
        <p>Корзина пуста</p>
        <p style="font-size:0.8rem">Добавь блюда из меню</p>
        <button class="btn-primary" onclick="goBack()">← Вернуться в меню</button>
      </div>`;
    return;
  }

  const total = cartItems.reduce((s, i) => s + i.price * i.qty, 0);
  const count = cartItems.reduce((s, i) => s + i.qty, 0);

  const rows = cartItems.map((item, idx) => `
    <div class="order-row">
      <span class="order-row-emoji">${item.emoji}</span>
      <span class="order-row-name">${item.name}</span>
      <div class="order-row-controls">
        <button class="qty-btn" onclick="changeQty(${idx}, -1)">−</button>
        <span class="qty-num">${item.qty}</span>
        <button class="qty-btn" onclick="changeQty(${idx}, 1)">+</button>
      </div>
      <span class="order-row-price">${item.price * item.qty}₽</span>
    </div>`).join('');

  body.innerHTML = `
    <div class="order-section-label">Блюда (${count} поз.)</div>
    <div class="order-list">${rows}</div>
    <div class="order-total-card">
      <span class="order-total-label">Итого</span>
      <span class="order-total-sum">${total}₽</span>
      <div class="order-total-note">
        👨‍🍳 Покажите этот экран официанту — они примут заказ без ошибок.
        <br>Кафе Чихо · ул. Советская, 10 · Кострома
      </div>
    </div>
    <div style="height:20px"></div>`;
}

function changeQty(idx, delta) {
  if (!cartItems[idx]) return;
  cartItems[idx].qty += delta;
  if (cartItems[idx].qty <= 0) cartItems.splice(idx, 1);
  updateCartFab();
  renderOrderScreen();
}

