let chatBusy = false;
// Анти-повтор: запоминаем последний использованный индекс варианта для каждого ключа
const replyVariantIndex = {};

function detectKeywords(text) {
  const lower = text.toLowerCase();
  for (let i = 0; i < keywordReplies.length; i++) {
    const reply = keywordReplies[i];
    if (reply.keys.some(k => lower.includes(k))) {
      if (reply.variants && reply.variants.length > 0) {
        // Выбираем следующий вариант, избегая предыдущего
        const prev = replyVariantIndex[i] !== undefined ? replyVariantIndex[i] : -1;
        let next;
        if (reply.variants.length > 1) {
          do { next = Math.floor(Math.random() * reply.variants.length); } while (next === prev);
        } else { next = 0; }
        replyVariantIndex[i] = next;
        return reply.variants[next];
      }
      return reply; // старый формат (msg + quick напрямую)
    }
  }
  return null;
}

function sendQuickReply(btn, text) {
  if (chatBusy) return;
  if (screenActions[text]) { goTo(screenActions[text]); return; }
  chatBusy = true;
  document.querySelectorAll('.qr-chip').forEach(b => { b.onclick = null; b.style.opacity = '0.5'; });
  addUserMsg(text);
  showTyping();
  // Точное совпадение имеет приоритет над keyword-поиском
  const reply = aiRepliesFixed[text] || detectKeywords(text) || {
    msg: '🤔 Интересный вопрос! Давай уточним: что именно тебе хочется — острое, лёгкое, с мясом или рыбой? Или могу открыть всё меню.',
    quick: ['Хочу что-то острое', 'Хочу лёгкое', 'С морепродуктами', 'Показать меню']
  };
  setTimeout(() => { removeTyping(); addBotMsg(reply.msg, reply.quick); chatBusy = false; }, 1100);
}

