function sendChat() {
  if (chatBusy) return;
  const input = document.getElementById('chatInput');
  const text = input.value.trim();
  if (!text) return;
  input.value = '';
  chatBusy = true;
  addUserMsg(text);
  showTyping();
  const reply = detectKeywords(text) || aiRepliesFixed[text] || {
    msg: '🤖 Нейросеть анализирует... Попробуй описать: что хочешь (острое/лёгкое/сытное), или когда (завтрак/обед/ужин), или что конкретно (суп/лапша/рис/закуска).',
    quick: ['Что острое?', 'Что на ужин?', 'Что из лапши?', 'Показать меню']
  };
  setTimeout(() => { removeTyping(); addBotMsg(reply.msg, reply.quick); chatBusy = false; }, 1200);
}

function addUserMsg(text) {
  const area = document.getElementById('chatArea');
  if (!area) return;
  const div = document.createElement('div');
  div.className = 'chat-msg user';
  div.innerHTML = `<div class="msg-bubble">${text}</div><span class="msg-time">сейчас</span>`;
  area.appendChild(div);
  scrollChat();
}

function addBotMsg(text, quickRepliesArr) {
  const area = document.getElementById('chatArea');
  if (!area) return;
  const div = document.createElement('div');
  div.className = 'chat-msg bot';
  div.innerHTML = `<div class="msg-bubble">${text}</div><span class="msg-time">сейчас</span>`;
  area.appendChild(div);
  const qr = document.getElementById('quickReplies');
  if (qr && quickRepliesArr) {
    qr.innerHTML = quickRepliesArr.map(r => {
      const isAction = screenActions[r];
      return `<button class="qr-chip${isAction ? ' action-chip' : ''}" onclick="sendQuickReply(this, '${r}')">${isAction ? '→ ' : ''}${r}</button>`;
    }).join('');
  }
  scrollChat();
}

function showTyping() {
  const area = document.getElementById('chatArea');
  if (!area) return;
  const div = document.createElement('div');
  div.className = 'chat-msg bot typing-indicator';
  div.id = 'typingIndicator';
  div.innerHTML = `<div class="msg-bubble"><span class="dot"></span><span class="dot"></span><span class="dot"></span></div>`;
  area.appendChild(div);
  scrollChat();
}

function removeTyping() {
  const t = document.getElementById('typingIndicator');
  if (t) t.remove();
}

function scrollChat() {
  const area = document.getElementById('chatArea');
  if (area) {
    const body = area.closest('.screen-body');
    if (body) setTimeout(() => body.scrollTop = body.scrollHeight, 50);
  }
}

document.addEventListener('DOMContentLoaded', () => {
  const input = document.getElementById('chatInput');
  if (input) input.addEventListener('keydown', (e) => { if (e.key === 'Enter') sendChat(); });
  initMenu();
  initQuest();
});

