function selectMood(btn) {
  document.querySelectorAll('.mood-card').forEach(c => c.classList.remove('selected'));
  btn.classList.add('selected');
  const mood = btn.dataset.mood;
  const pool = moodPools[mood];
  if (!pool) return;
  // Случайно выбираем одно из 5
  const data = pool[Math.floor(Math.random() * pool.length)];
  const result = document.getElementById('moodResult');
  document.getElementById('moodDish').textContent = data.dish;
  document.getElementById('moodReason').textContent = data.reason;
  result.classList.remove('hidden');
  // Добавляем кнопку "Другой вариант"
  const rerollBtn = document.getElementById('moodRerollBtn');
  if (rerollBtn) rerollBtn.onclick = () => selectMood(btn);
  setTimeout(() => result.scrollIntoView({ behavior: 'smooth', block: 'nearest' }), 100);
}

